mapper.select:
/* 1. ID: selectList 2. 업무명: 관리자의 리스트 3. 업무설명: */ SELECT * FROM ( SELECT store_id ,party_cd ,bis_num ,store_cell_num ,store_ceo_nm ,store_nm ,store_img ,store_addr ,store_event ,store_kakao_id ,store_latitude ,store_longitude from CRBN_STORE_INFO where party_cd = #{partyCd}
and store_nm like CONCAT('%',#{storeNm},'%')
ORDER BY store_nm ) A LIMIT #{pageNo}, #{listSize}
